@Composable
private fun ShimmerTournamentCardPlaceholder() {
 val transition = rememberInfiniteTransition(label = "shimmer")
 val shimmerX by transition.animateFloat(
 initialValue = 0f,
 targetValue = 1000f,
 animationSpec = infiniteRepeatable(
 animation = tween(durationMillis = 1100, easing = FastOutSlowInEasing),
 repeatMode = RepeatMode.Restart
 ), label = "x"
 )
 val shimmerColors = listOf(
 NetwinTokens.Surface.copy(alpha = 0.9f),
 NetwinTokens.SurfaceAlt.copy(alpha = 0.6f),
 NetwinTokens.Surface.copy(alpha = 0.9f)
 )
 val brush = Brush.linearGradient(
 colors = shimmerColors,
 start = Offset(shimmerX, 0f),
 end = Offset(shimmerX + 200f, 0f)
 )

 Card(
 modifier = Modifier
 .fillMaxWidth()
 .padding(horizontal = NetwinTokens.Sp16),
 shape = RoundedCornerShape(NetwinTokens.RadiusLg),
 colors = CardDefaults.cardColors(containerColor = NetwinTokens.Surface)
 ) {
 Column(modifier = Modifier.padding(NetwinTokens.Sp14)) {
 // Title line
 Box(
 modifier = Modifier
 .fillMaxWidth(0.6f)
 .height(18.dp)
 .clip(RoundedCornerShape(6.dp))
 .background(brush)
 )
 Spacer(Modifier.height(NetwinTokens.Sp10))
 // Chips row
 Row(horizontalArrangement = Arrangement.spacedBy(NetwinTokens.Sp8)) {
 repeat(3) {
 Box(
 modifier = Modifier
 .width(90.dp)
 .height(24.dp)
 .clip(RoundedCornerShape(12.dp))
 .background(brush)
 )
 }
 }
 Spacer(Modifier.height(NetwinTokens.Sp10))
 // Capacity bar
 Box(
 modifier = Modifier
 .fillMaxWidth()
 .height(10.dp)
 .clip(RoundedCornerShape(6.dp))
 .background(brush)
 )
 Spacer(Modifier.height(NetwinTokens.Sp12))
 // Buttons row
 Row(horizontalArrangement = Arrangement.spacedBy(NetwinTokens.Sp8)) {
 Box(
 modifier = Modifier
 .weight(1f)
 .height(40.dp)
 .clip(RoundedCornerShape(NetwinTokens.RadiusSm))
 .background(brush)
 )
 Box(
 modifier = Modifier
 .weight(1f)
 .height(40.dp)
 .clip(RoundedCornerShape(NetwinTokens.RadiusSm))
 .background(brush)
 )
 }
 }
 }
}

