 modifier = Modifier.size(24.dp)
 )
 Spacer(modifier = Modifier.height(4.dp))
 Text(
 text = value,
 color = Color.White,
 fontSize = 16.sp,
 fontWeight = FontWeight.Bold
 )
 Text(
 text = label,
 color = NetwinTokens.TextSecondary,
 fontSize = 12.sp
 )
 }
}


