fun TournamentsScreenUI(navController: NavController, viewModel: TournamentViewModel = hiltViewModel()) {
 if (FeatureFlags.isTournamentUiV2()) {
 TournamentsScreenNewUI(navController = navController, viewModel = viewModel)
 } else {
 LegacyTournamentsScreenUI(navController = navController, viewModel = viewModel)
 }
}

// Neon gradient countdown chip used on banner or inline (top-level)
@Composable
private fun CountdownBadge(targetTimeMillis: Long) {
 var remaining by remember(targetTimeMillis) {
 mutableStateOf(maxOf(0L, targetTimeMillis - System.currentTimeMillis()))
 }
 LaunchedEffect(targetTimeMillis) {
 while (remaining > 0) {
 delay(1000)
 remaining = maxOf(0L, targetTimeMillis - System.currentTimeMillis())
 }
 }

 val text = remember(remaining) { formatRemaining(remaining) }
 val cd = remember(remaining) { accessibleCountdown(remaining) }

 Box(
 modifier = Modifier
 .semantics { contentDescription = cd }
 .border(1.dp, NetwinTokens.Accent.copy(alpha = 0.6f), RoundedCornerShape(10.dp))
 .clip(RoundedCornerShape(10.dp))
 .background(
 brush = Brush.horizontalGradient(listOf(NetwinTokens.Primary, NetwinTokens.Accent))
 )
 .padding(horizontal = NetwinTokens.Sp12, vertical = NetwinTokens.Sp6)
 ) {
 Text(
 text = text,
 color = Color.White,
 style = MaterialTheme.typography.labelLarge,
 fontWeight = FontWeight.ExtraBold,
 fontFamily = FontFamily.Monospace
 )
 }
}

private fun formatRemaining(ms: Long): String {
 if (ms <= 0L) return "Starting…"
 val totalSec = ms / 1000
 val days = totalSec / (24 * 3600)
 val hours = (totalSec % (24 * 3600)) / 3600
 val minutes = (totalSec % 3600) / 60
 val seconds = totalSec % 60
 return if (days > 0) {
 String.format("%02d:%02d:%02d:%02d", days, hours, minutes, seconds)
 } else {
 String.format("%02d:%02d:%02d", hours, minutes, seconds)
 }
}

private fun accessibleCountdown(ms: Long): String {
 if (ms <= 0L) return "Starting"
 val totalSec = ms / 1000
 val hours = totalSec / 3600
 val minutes = (totalSec % 3600) / 60
 val seconds = totalSec % 60
 return "Starts in ${hours} hours, ${minutes} minutes, ${seconds} seconds"
}

@Composable
fun TournamentsScreenNewUI(navController: NavController, viewModel: TournamentViewModel = hiltViewModel()) {
 val state by viewModel.state.collectAsState()
 val walletBalance by viewModel.walletBalance.collectAsState()
 val userName by viewModel.userName.collectAsState()
 val isRefreshing by viewModel.isRefreshing.collectAsState()
 val refreshError by viewModel.refreshError.collectAsState()
 val refreshSuccess by viewModel.refreshSuccess.collectAsState()

 val tournamentState = state as? TournamentState ?: TournamentState()
 val tournaments = tournamentState.tournaments
 val isLoading = tournamentState.isLoading
 val error = tournamentState.error

 // Local UI state: tabs and search
 val tabs = listOf("All", "Upcoming", "Live", "Completed")
 var selectedTab by remember { mutableStateOf(0) }
 var searchQuery by remember { mutableStateOf("") }

 // Filter by tab
 val statusFiltered = remember(tournaments, selectedTab) {
 when (tabs[selectedTab]) {
 "Upcoming" -> tournaments.filter { it.computedStatus == TournamentStatus.UPCOMING || it.computedStatus == TournamentStatus.STARTS_SOON }
 "Live" -> tournaments.filter { it.computedStatus == TournamentStatus.ONGOING || it.computedStatus == TournamentStatus.ROOM_OPEN }
 "Completed" -> tournaments.filter { it.computedStatus == TournamentStatus.COMPLETED }
 else -> tournaments
 }
 }
 // Filter by search
 val visibleTournaments = remember(statusFiltered, searchQuery) {
 val q = searchQuery.trim().lowercase()
 if (q.isEmpty()) statusFiltered else statusFiltered.filter { t ->
 t.name.lowercase().contains(q) || t.map.lowercase().contains(q)
 }
 }

 Scaffold(
 topBar = {
 TournamentsTopBar(
 walletBalance = walletBalance.toInt(),
 currency = "INR",
 isRefreshing = false,
 onToggleUi = null
 )
 }
 ) { paddingValues ->
 PullRefreshComponent(
 isRefreshing = isRefreshing,
 refreshError = refreshError,
 refreshSuccess = refreshSuccess,
 onRefresh = { viewModel.handleEvent(TournamentEvent.RefreshTournaments(force = true)) },
 onClearRefreshSuccess = { viewModel.clearRefreshSuccess() },
 onClearRefreshError = { viewModel.clearRefreshError() }
 ) {
 if (isLoading && tournaments.isEmpty()) {
 // Shimmer placeholders during initial load
 LazyColumn(
 modifier = Modifier
 .fillMaxSize()
 .background(NetwinTokens.Background)
 .padding(paddingValues),
 contentPadding = PaddingValues(bottom = NetwinTokens.Sp24, top = NetwinTokens.Sp12),
 verticalArrangement = Arrangement.spacedBy(NetwinTokens.Sp12)
 ) {
 items(6) { _ -> ShimmerTournamentCardPlaceholder() }
 }
 } else if (error != null) {
 Box(
 modifier = Modifier
 .fillMaxSize()
 .background(NetwinTokens.Background)
 .padding(paddingValues),
 contentAlignment = Alignment.Center
 ) {
 Column(horizontalAlignment = Alignment.CenterHorizontally) {
 Text("Something went wrong", color = NetwinTokens.TextPrimary)
 Spacer(Modifier.height(NetwinTokens.Sp8))
 OutlinedButton(onClick = { viewModel.handleEvent(TournamentEvent.RefreshTournaments(force = true)) }) {
 Text("Retry")
 }
 }
 }
 } else if (tournaments.isEmpty()) {
 Box(
 modifier = Modifier
 .fillMaxSize()
 .background(NetwinTokens.Background)
 .padding(paddingValues),
 contentAlignment = Alignment.Center
 ) {
 Column(horizontalAlignment = Alignment.CenterHorizontally) {
 Text("No tournaments available", color = NetwinTokens.TextSecondary)
 Spacer(Modifier.height(NetwinTokens.Sp8))
 OutlinedButton(onClick = { viewModel.handleEvent(TournamentEvent.RefreshTournaments(force = true)) }) {
 Text("Refresh")
 }
 }
 }
 } else {
 LazyColumn(
 modifier = Modifier
 .fillMaxSize()
 .background(NetwinTokens.Background)
 .padding(paddingValues),
 contentPadding = PaddingValues(bottom = NetwinTokens.Sp24, top = NetwinTokens.Sp12),
 verticalArrangement = Arrangement.spacedBy(NetwinTokens.Sp12)
 ) {
 item {
 Text(
 text = "Discover Tournaments",
 color = NetwinTokens.TextPrimary,
 style = MaterialTheme.typography.headlineSmall,
 fontWeight = FontWeight.ExtraBold,
 modifier = Modifier.padding(horizontal = NetwinTokens.Sp16)
 )
 Spacer(Modifier.height(NetwinTokens.Sp4))
 Text(
 text = "Curated for you, $userName",
 color = NetwinTokens.TextSecondary,
 style = MaterialTheme.typography.bodyMedium,
 modifier = Modifier.padding(horizontal = NetwinTokens.Sp16)
 )
 Spacer(Modifier.height(NetwinTokens.Sp12))
 TournamentsSearchBar(
 query = searchQuery,
 onQueryChange = { searchQuery = it }
 )
 Spacer(Modifier.height(NetwinTokens.Sp8))
 TournamentsTabs(
 tabs = tabs,
 selectedIndex = selectedTab,
 onSelect = { selectedTab = it }
 )
 }

 items(visibleTournaments) { t ->
 TournamentCardV2(
 t = t,
 onDetailsClick = { navController.navigate(Screen.TournamentDetails.createRoute(t.id)) },
 onRegisterClick = {
 navController.navigate(
 TournamentRegistration(
 tournamentId = t.id,
 stepIndex = 1
 )
 )
 }
 )
 }
 }
 }
 }
 }
}

@Composable
private fun TournamentsSearchBar(
 query: String,
 onQueryChange: (String) -> Unit
) {
 Surface(
 color = NetwinTokens.Surface,
 shape = RoundedCornerShape(12.dp),
 modifier = Modifier
 .fillMaxWidth()
 .padding(horizontal = NetwinTokens.Sp16)
 ) {
 Row(
 modifier = Modifier.padding(horizontal = NetwinTokens.Sp12, vertical = NetwinTokens.Sp8),
 verticalAlignment = Alignment.CenterVertically
 ) {
 Icon(
 imageVector = Icons.Default.Search,
 contentDescription = null,
 tint = NetwinTokens.TextSecondary,
 modifier = Modifier.size(18.dp)
 )
 Spacer(Modifier.width(NetwinTokens.Sp8))
 androidx.compose.material3.TextField(
 value = query,
 onValueChange = onQueryChange,
 modifier = Modifier.fillMaxWidth(),
 placeholder = { Text("Search tournaments", color = NetwinTokens.TextSecondary) },
 textStyle = MaterialTheme.typography.bodyMedium,
 singleLine = true,
 colors = androidx.compose.material3.TextFieldDefaults.colors(
 focusedContainerColor = Color.Transparent,
 unfocusedContainerColor = Color.Transparent,
 focusedTextColor = NetwinTokens.TextPrimary,
 unfocusedTextColor = NetwinTokens.TextPrimary,
 cursorColor = NetwinTokens.Primary,
 focusedIndicatorColor = Color.Transparent,
 unfocusedIndicatorColor = Color.Transparent
 )
 )
 }
 }
}

@Composable
private fun TournamentsTabs(
 tabs: List<String>,
 selectedIndex: Int,
 onSelect: (Int) -> Unit
) {
 Row(
 modifier = Modifier
 .fillMaxWidth()
 .padding(horizontal = NetwinTokens.Sp16),
 horizontalArrangement = Arrangement.spacedBy(NetwinTokens.Sp8)
 ) {
 tabs.forEachIndexed { index, label ->
 val selected = index == selectedIndex
 OutlinedButton(
 onClick = { onSelect(index) },
 shape = RoundedCornerShape(10.dp),
 border = BorderStroke(1.dp, if (selected) NetwinTokens.Primary else NetwinTokens.Primary.copy(alpha = 0.2f)),
 colors = ButtonDefaults.outlinedButtonColors(
 containerColor = NetwinTokens.Surface,
 contentColor = if (selected) NetwinTokens.TextPrimary else NetwinTokens.TextSecondary
 ),
 contentPadding = PaddingValues(horizontal = NetwinTokens.Sp12, vertical = NetwinTokens.Sp6)
 ) {
 Text(label, fontWeight = if (selected) FontWeight.SemiBold else FontWeight.Normal)
 }
 }
 }
}

@Composable
private fun TournamentCardV2(
 t: Tournament,
 onDetailsClick: () -> Unit,
 onRegisterClick: () -> Unit
) {
 Card(
 modifier = Modifier
 .fillMaxWidth()
 .padding(horizontal = NetwinTokens.Sp16)
 .border(
 width = 1.dp,
 brush = Brush.horizontalGradient(
 listOf(
 NetwinTokens.Primary.copy(alpha = 0.12f),
 NetwinTokens.Accent.copy(alpha = 0.12f)
 )
 ),
 shape = RoundedCornerShape(NetwinTokens.RadiusLg)
 )
 .clip(RoundedCornerShape(NetwinTokens.RadiusLg)),
 colors = CardDefaults.cardColors(containerColor = NetwinTokens.SurfaceAlt)
 ) {
 Column(modifier = Modifier.padding(NetwinTokens.Sp14)) {
 // Banner with overlay and countdown (if available)
 if (!t.bannerImage.isNullOrBlank()) {
 Box(modifier = Modifier
 .fillMaxWidth()
 .height(140.dp)
 .clip(RoundedCornerShape(topStart = NetwinTokens.RadiusLg, topEnd = NetwinTokens.RadiusLg))
 ) {
 AsyncImage(
 model = t.bannerImage,
 contentDescription = "Tournament banner",
 contentScale = ContentScale.Crop,
 modifier = Modifier.matchParentSize()
 )
 // Gradient overlay for legibility
 Box(
 modifier = Modifier
 .matchParentSize()
 .background(
 Brush.verticalGradient(
 colors = listOf(Color.Transparent, Color(0xAA000000))
 )
 )
 )
 // Top row: status badge
 Row(
 modifier = Modifier
 .fillMaxWidth()
 .padding(NetwinTokens.Sp12),
 horizontalArrangement = Arrangement.Start,
 verticalAlignment = Alignment.CenterVertically
 ) {
 TournamentStatusBadge(status = t.computedStatus)
 }
 // Countdown moved outside the banner to avoid covering image
 }
 Spacer(Modifier.height(NetwinTokens.Sp12))
 }

 // Title and meta
 Row(
 modifier = Modifier.fillMaxWidth(),
 horizontalArrangement = Arrangement.SpaceBetween,
 verticalAlignment = Alignment.CenterVertically
 ) {
 Column(modifier = Modifier.weight(1f)) {
 Text(
 text = t.name,
 color = NetwinTokens.TextPrimary,
 style = MaterialTheme.typography.titleMedium,
 fontWeight = FontWeight.ExtraBold,
 maxLines = 1,
 overflow = TextOverflow.Ellipsis
 )
 Spacer(Modifier.height(NetwinTokens.Sp4))
 Row(verticalAlignment = Alignment.CenterVertically) {
 ModeChip(mode = t.mode)
 Spacer(Modifier.width(NetwinTokens.Sp8))
 Icon(
 imageVector = Icons.Default.PinDrop,
 contentDescription = null,
 tint = NetwinTokens.Primary,
 modifier = Modifier.size(16.dp)
 )
 Spacer(Modifier.width(NetwinTokens.Sp4))
 Text(
 text = t.map,
 color = NetwinTokens.TextSecondary,
 style = MaterialTheme.typography.bodySmall
 )
 }
 }
 }

 Spacer(Modifier.height(NetwinTokens.Sp10))
 Row(
 modifier = Modifier.fillMaxWidth(),
 horizontalArrangement = Arrangement.SpaceBetween
 ) {
 // Choose palette based on preview toggle
 val prizeColorV2 = if (USE_ALT_ACCENTS) NetwinTokens.Primary.copy(alpha = 0.92f) else Color(0xFFFFC107)
 val perKillColorV2 = if (USE_ALT_ACCENTS) NetwinTokens.Tertiary.copy(alpha = 0.92f) else Color(0xFF26C6DA)
 val entryPaidColorV2 = if (USE_ALT_ACCENTS) NetwinTokens.Accent.copy(alpha = 0.92f) else Color(0xFFFF7043)
 InfoChip(
 label = "Prize Pool",
 value = tidyMoney(NGNTransactionUtils.formatAmount(t.prizePool.toDouble(), "INR")),
 valueColor = prizeColorV2 // premium highlight
 )
 InfoChip(
 label = "Per Kill",
 value = tidyMoney(NGNTransactionUtils.formatAmount(t.killReward ?: 0.0, "INR")),
 valueColor = perKillColorV2 // calm accent
 )
 InfoChip(
 label = "Entry Fee",
 value = if (t.entryFee > 0) tidyMoney(NGNTransactionUtils.formatAmount(t.entryFee.toDouble(), "INR")) else "Free",
 valueColor = if (t.entryFee > 0) entryPaidColorV2 else Color(0xFF4CAF50) // Deep orange for paid, green for Free
 )
 }
 // Countdown between currency row and capacity
 if (t.computedStatus == TournamentStatus.UPCOMING || t.computedStatus == TournamentStatus.STARTS_SOON) {
 Spacer(Modifier.height(NetwinTokens.Sp6))
 Row(
 modifier = Modifier.fillMaxWidth(),
 horizontalArrangement = Arrangement.Start
 ) {
 Box(modifier = Modifier.scale(0.9f)) { // subtle size reduction for visual balance
 CountdownBadge(targetTimeMillis = t.startTime)
 }
 }
 }
 // Subtle divider for hierarchy
 Spacer(Modifier.height(NetwinTokens.Sp6))
 Divider(
 color = NetwinTokens.Primary.copy(alpha = 0.08f),
 thickness = 0.5.dp
 )
 Spacer(Modifier.height(NetwinTokens.Sp8))
 TournamentCapacityIndicator(
 registeredTeams = t.registeredTeams,
 maxTeams = t.maxTeams
 )
 Spacer(Modifier.height(NetwinTokens.Sp10))
 Row(horizontalArrangement = Arrangement.spacedBy(NetwinTokens.Sp8)) {
 OutlinedButton(
 onClick = onDetailsClick,
 modifier = Modifier.weight(1f),
 shape = RoundedCornerShape(NetwinTokens.RadiusSm),
 colors = ButtonDefaults.outlinedButtonColors(contentColor = NetwinTokens.Primary),
 border = BorderStroke(1.dp, NetwinTokens.Primary)
 ) { Text("Details", fontWeight = FontWeight.SemiBold, color = NetwinTokens.Primary) }

 GradientPrimaryButton(
 text = "Register",
 modifier = Modifier.weight(1f),
 onClick = onRegisterClick
 )
 }
 }
 }
}

