// Helper functions
internal fun formatDate(timestamp: Long?): String {
 if (timestamp == null) return "N/A"
 val sdf = SimpleDateFormat("dd MMM yyyy, hh:mm a", Locale.getDefault())
 return sdf.format(Date(timestamp))
}

