@Composable
fun TournamentCard(
 tournament: Tournament,
 viewModel: TournamentViewModel,
 onCardClick: () -> Unit,
 navController: NavController,
 currency: String
) {
 // ... existing code ...

 Card(
 modifier = Modifier
 .fillMaxWidth()
 .padding(horizontal = 16.dp)
 .clickable(onClick = onCardClick),
 shape = RoundedCornerShape(12.dp),
 colors = CardDefaults.cardColors(
 containerColor = NetwinTokens.SurfaceAlt
 ),
 elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
 ) {
 Column { // Main content column for the card
 // ... existing code ...

 Box(
 modifier = Modifier
 .height(140.dp)
 .fillMaxWidth()
 ) {
 // Background placeholder or Image
 if (tournament.bannerImage.isNullOrEmpty()) {
 Box(
 modifier = Modifier
 .fillMaxSize()
 .background(
 brush = Brush.verticalGradient(
 colors = listOf(NetwinTokens.Surface, NetwinTokens.SurfaceAlt)
 )
 )
 )
 // Centered Info when no image
 Box(
 modifier = Modifier.fillMaxSize(),
 contentAlignment = Alignment.Center
 ) {
 Column(
 horizontalAlignment = Alignment.CenterHorizontally,
 verticalArrangement = Arrangement.Center,
 modifier = Modifier.padding(8.dp)
 ) {
 Icon(
 Icons.Default.EmojiEvents,
 contentDescription = "Tournament Event",
 tint = NetwinTokens.Tertiary,
 modifier = Modifier.size(40.dp)
 )
 Spacer(modifier = Modifier.height(8.dp))
 Text(
 text = tournament.name,
 color = Color.White,
 style = MaterialTheme.typography.titleSmall,
 fontWeight = FontWeight.Bold,
 maxLines = 1,
 overflow = TextOverflow.Ellipsis
 )
 Spacer(modifier = Modifier.height(4.dp))
 Text(
 text = tournament.map,
 color = Color.White.copy(alpha = 0.8f),
 style = MaterialTheme.typography.bodySmall,
 textAlign = TextAlign.Center
 )
 }
 }
 } else {
 AsyncImage(
 model = tournament.bannerImage,
 contentDescription = "Tournament Banner: ${tournament.name}",
 contentScale = ContentScale.Crop,
 modifier = Modifier.fillMaxSize()
 )
 }

 // ... existing code ...

 Row(
 verticalAlignment = Alignment.CenterVertically,
 horizontalArrangement = Arrangement.spacedBy(4.dp)
 ) {
 Icon(
 Icons.Default.PinDrop,
 contentDescription = "Map",
 tint = NetwinTokens.Tertiary,
 modifier = Modifier.size(16.dp)
 )
 Text(
 text = tournament.map,
 style = MaterialTheme.typography.bodyMedium,
 color = Color.White.copy(alpha = 0.8f)
 )
 }

 // Info chips row
 Row(
 modifier = Modifier.fillMaxWidth(),
 horizontalArrangement = Arrangement.SpaceBetween
 ) {
 // Choose palette based on preview toggle
 val prizeColorLegacy = if (USE_ALT_ACCENTS) NetwinTokens.Primary.copy(alpha = 0.92f) else Color(0xFFFFC107)
 val perKillColorLegacy = if (USE_ALT_ACCENTS) NetwinTokens.Tertiary.copy(alpha = 0.92f) else Color(0xFF26C6DA)
 val entryPaidColorLegacy = if (USE_ALT_ACCENTS) NetwinTokens.Accent.copy(alpha = 0.92f) else Color(0xFFFF7043)
 InfoChip(
 label = "Prize Pool",
 value = tidyMoney(NGNTransactionUtils.formatAmount(tournament.prizePool.toDouble(), currency)),
 valueColor = prizeColorLegacy
 )
 InfoChip(
 label = "Per Kill",
 value = tidyMoney(NGNTransactionUtils.formatAmount(tournament.killReward ?: 0.0, currency)),
 valueColor = perKillColorLegacy
 )
 InfoChip(
 label = "Entry Fee",
 value = if (tournament.entryFee > 0) tidyMoney(NGNTransactionUtils.formatAmount(tournament.entryFee.toDouble(), currency)) else "Free",
 valueColor = if (tournament.entryFee > 0) entryPaidColorLegacy else Color(0xFF4CAF50)
 )
 }
 // Countdown between currency row and capacity (legacy)
 if (tournament.computedStatus == TournamentStatus.UPCOMING || tournament.computedStatus == TournamentStatus.STARTS_SOON) {
 Spacer(Modifier.height(NetwinTokens.Sp6))
 Row(
 modifier = Modifier.fillMaxWidth(),
 horizontalArrangement = Arrangement.Start
 ) {
 Box(modifier = Modifier.scale(0.9f)) {
 CountdownBadge(targetTimeMillis = tournament.startTime)
 }
 }
 }
 // Subtle divider for hierarchy (legacy)
 Spacer(Modifier.height(NetwinTokens.Sp6))
 Divider(
 color = NetwinTokens.Primary.copy(alpha = 0.08f),
 thickness = 0.5.dp
 )
 Spacer(Modifier.height(NetwinTokens.Sp8))
 TournamentCapacityIndicator(
 registeredTeams = tournament.registeredTeams,
 maxTeams = tournament.maxTeams,
 modifier = Modifier.padding(top = 4.dp, bottom = 8.dp)
 )

 // Simplified: Registration button without ViewModel-bound state variables
 val isFull = tournament.maxTeams <= tournament.registeredTeams
 val statusAllows = tournament.computedStatus == TournamentStatus.UPCOMING ||
 tournament.computedStatus == TournamentStatus.ROOM_OPEN ||
 tournament.computedStatus == TournamentStatus.STARTS_SOON
 val canRegister = statusAllows && !isFull

 if (statusAllows) {
 GradientPrimaryButton(
 text = if (isFull) "Tournament Full" else "Join Tournament",
 modifier = Modifier
 .fillMaxWidth()
 .height(48.dp),
 enabled = !isFull,
 onClick = {
 if (!isFull) {
 navController.navigate(
 TournamentRegistration(
 tournamentId = tournament.id,
 stepIndex = 1
 )
 )
 }
 }
 )
 } else if (tournament.computedStatus == TournamentStatus.COMPLETED) {
 Text(
 textAlign = TextAlign.Center,
 text = "Tournament Ended",
 color = Color.White.copy(alpha = 0.7f),
 style = MaterialTheme.typography.bodyMedium,
 modifier = Modifier
 .fillMaxWidth()
 .padding(vertical = 12.dp)
 )
 }
 }
 }
 }
}


