@Composable
fun TournamentStatusBadge(
 status: TournamentStatus,
 modifier: Modifier = Modifier
) {
 val (color, icon, label) = when (status) {
 TournamentStatus.ONGOING -> Triple(NetwinTokens.Accent, Icons.Filled.Videocam, "LIVE")
 TournamentStatus.UPCOMING -> Triple(NetwinTokens.Primary, Icons.Filled.Event, "UPCOMING")
 TournamentStatus.STARTS_SOON -> Triple(NetwinTokens.Accent.copy(alpha = 0.85f), Icons.Filled.Schedule, "STARTS SOON")
 TournamentStatus.ROOM_OPEN -> Triple(NetwinTokens.Primary.copy(alpha = 0.9f), Icons.Filled.LockOpen, "ROOM OPEN")
 TournamentStatus.COMPLETED -> Triple(NetwinTokens.TextSecondary, Icons.Filled.CheckCircle, "COMPLETED")
 }
 Surface(
 modifier = modifier,
 color = Color.Transparent
 ) {
 Row(
 modifier = Modifier
 .background(color, shape = RoundedCornerShape(6.dp))
 .padding(horizontal = 10.dp, vertical = 4.dp),
 verticalAlignment = Alignment.CenterVertically
 ) {
 Icon(icon, contentDescription = null, tint = Color.White, modifier = Modifier.size(16.dp))
 Spacer(Modifier.width(4.dp))
 Text(
 text = label,
 color = Color.White,
 fontWeight = FontWeight.Bold,
 fontSize = 12.sp
 )
 }
 }
}

@Composable
fun GradientPrimaryButton(
 text: String,
 modifier: Modifier = Modifier,
 enabled: Boolean = true,
 onClick: () -> Unit
) {
 Button(
 onClick = onClick,
 enabled = enabled,
 modifier = modifier
 .clip(RoundedCornerShape(NetwinTokens.RadiusSm))
 .background(Brush.horizontalGradient(listOf(NetwinTokens.Primary, NetwinTokens.Accent))),
 shape = RoundedCornerShape(NetwinTokens.RadiusSm),
 colors = ButtonDefaults.buttonColors(
 containerColor = Color.Transparent,
 contentColor = Color.White,
 disabledContainerColor = Color.DarkGray.copy(alpha = 0.5f),
 disabledContentColor = Color.White.copy(alpha = 0.5f)
 )
 ) {
 Text(text = text, fontWeight = FontWeight.SemiBold)
 }
}

